html:
{# ==============================
   PURCHASE ORDER (COMPACT TABLE + TERMS + CONTACT + 3 SIGNATURES)
   - Uses Letterhead ({{ letter_head }})
   - Compact items table (smaller padding/font) for long descriptions
   - Terms & Conditions (doc.terms)
   - Contact footer
================================ #}

{% macro _val(v, fallback="-") %}{{ v if v not in (None, "", []) else fallback }}{% endmacro %}

{% set po_date = doc.transaction_date or doc.get("date") or doc.get("posting_date") or "" %}
{% set supplier_name = doc.supplier_name or doc.supplier or "" %}

{# Prepared / Reviewed / Approved users #}
{% set prepared_by_user = doc.owner %}
{% set prepared_by = frappe.db.get_value("User", prepared_by_user, "full_name") or prepared_by_user %}

{% set reviewed_by_user = doc.modified_by if doc.docstatus == 1 else "" %}
{% set reviewed_by = (frappe.db.get_value("User", reviewed_by_user, "full_name") or reviewed_by_user) if reviewed_by_user else "" %}

{% set approved_by_user = doc.get("approved_by") or (doc.modified_by if doc.docstatus == 1 else "") %}
{% set approved_by = (frappe.db.get_value("User", approved_by_user, "full_name") or approved_by_user) if approved_by_user else "" %}

<style>
  .po-wrap{
    font-family: "Segoe UI", Tahoma, Arial, sans-serif;
    font-size: 12px;
    color:#1f2d3d;
  }

  .po-title{ text-align:center; margin: 6px 0 10px 0; }
  .po-title h2{
    margin:0; font-size: 18px; letter-spacing: .7px; text-transform: uppercase;
  }
  .po-title .ref{ margin-top: 3px; color:#6c757d; font-size: 10.8px; }

  .po-divider{ border:0; border-top:1px solid #212529; margin: 8px 0 12px 0; opacity:.8; }

  .po-grid{ width:100%; border-collapse: collapse; table-layout: fixed; }
  .po-grid td{ padding: 5px 7px; vertical-align: top; }
  .po-field-label{ font-weight: 800; color:#212529; width: 22%; white-space: nowrap; }
  .po-field-value{ width: 28%; }

  .po-card{
    margin-top: 12px;
    border: 1px solid #e9ecef;
    border-radius: 8px;
    padding: 10px 12px;
    background: #fbfcfd;
  }
  .po-section-title{ font-weight: 900; margin-bottom: 7px; color:#212529; font-size: 11.8px; }

  /* COMPACT items table */
  .po-items{
    width:100%;
    border-collapse: collapse;
    table-layout: fixed;
    background:#fff;
    border: 1px solid #e9ecef;
    border-radius: 8px;
    overflow: hidden;
    font-size: 11.2px;           /* smaller */
  }
  .po-items th, .po-items td{
    padding: 5px 6px;            /* smaller padding */
    border-bottom: 1px solid #eef2f6;
    vertical-align: top;
  }
  .po-items th{
    font-weight: 900;
    font-size: 11px;
    color:#212529;
    background: #f7f9fb;
  }
  .po-items tr:last-child td{ border-bottom: 0; }

  .t-center{ text-align:center; }
  .t-right{ text-align:right; font-variant-numeric: tabular-nums; white-space: nowrap; }

  /* Force description to WRAP and not expand table */
  .desc{
    white-space: normal;
    word-break: break-word;
    line-height: 1.25;
  }
  .muted{ color:#6c757d; font-weight: 600; }

  /* Totals compact */
  .po-totals{
    width: 330px;
    margin-left: auto;
    border-collapse: collapse;
    font-size: 11.4px;
  }
  .po-totals td{ padding: 5px 2px; font-variant-numeric: tabular-nums; }
  .po-totals .k{ font-weight: 800; color:#212529; width: 60%; }
  .po-totals .v{ text-align:right; width: 40%; font-weight: 900; }
  .po-totals .line td{ padding-top: 7px; border-top: 1px dashed #cfd8e3; }

  /* 3 signatures */
  .po-sign-row{
    margin-top: 34px;
    display:flex;
    justify-content: space-between;
    gap: 16px;
  }
  .po-sign-box{ width: 32%; text-align:center; }
  .po-sign-line{
    margin-top: 44px;
    border-top: 2px dashed #2f343a;
    padding-top: 6px;
    font-weight: 900;
    font-size: 11.8px;
  }
  .po-sign-meta{ margin-top: 4px; font-size: 10.8px; color:#212529; font-weight: 700; min-height: 14px; }
  .po-sign-note{ margin-top: 2px; color:#6c757d; font-size: 10.6px; font-weight: 600; }

  /* Terms + Contact */
  .po-terms{
    white-space: pre-wrap;
    line-height: 1.35;
    font-size: 11.2px;
  }
  .po-contact{
    margin-top: 14px;
    border-top: 1px solid #e9ecef;
    padding-top: 8px;
    display:flex;
    justify-content: space-between;
    gap: 12px;
    font-size: 10.8px;
    color:#6c757d;
  }
  .po-contact b{ color:#212529; }

  @media print{ .po-wrap{ margin:0; } }
</style>

<div class="po-wrap">
  {{ letter_head }}

  <div class="po-title">
    <h2>Purchase Order</h2>
    <div class="ref">PO No: {{ doc.name }}</div>
  </div>

  <hr class="po-divider">

  <!-- Main Info -->
  <table class="po-grid">
    <tr>
      <td class="po-field-label">Date</td>
      <td class="po-field-value">{{ _val(po_date) }}</td>

      <td class="po-field-label">Status</td>
      <td class="po-field-value">{{ _val(doc.status) }}</td>
    </tr>

    <tr>
      <td class="po-field-label">Supplier</td>
      <td class="po-field-value">{{ _val(supplier_name) }}</td>

      <td class="po-field-label">Currency</td>
      <td class="po-field-value">{{ _val(doc.currency) }}</td>
    </tr>
  </table>

  <!-- Items -->
  <div class="po-card">
    <div class="po-section-title">Items</div>

    <table class="po-items">
      <thead>
        <tr>
          <th class="t-center" style="width:36px;">#</th>
          <th>Description</th>
          <th class="t-right" style="width:70px;">Qty</th>
          <th class="t-center" style="width:55px;">UOM</th>
          <th class="t-right" style="width:80px;">Rate</th>
          <th class="t-right" style="width:92px;">Amount</th>
        </tr>
      </thead>
      <tbody>
        {% for it in (doc.items or []) %}
        <tr>
          <td class="t-center">{{ loop.index }}</td>
          <td class="desc">
            <div><b>{{ it.item_name or it.item_code or "-" }}</b></div>
            {# Only show extra description if it exists and is different #}
            {% if it.description and (it.description != (it.item_name or "")) %}
              <div class="muted">{{ it.description }}</div>
            {% endif %}
          </td>
          <td class="t-right">{{ it.qty or 0 }}</td>
          <td class="t-center">{{ it.uom or "-" }}</td>
          <td class="t-right">{{ frappe.utils.fmt_money(it.rate or 0, currency=doc.currency) }}</td>
          <td class="t-right">{{ frappe.utils.fmt_money(it.amount or 0, currency=doc.currency) }}</td>
        </tr>
        {% endfor %}
      </tbody>
    </table>

    <!-- Totals -->
    <div style="margin-top: 10px;">
      <table class="po-totals">
        <tr>
          <td class="k">Total Quantity</td>
          <td class="v">{{ doc.total_qty or 0 }}</td>
        </tr>
        <tr>
          <td class="k">Net Total</td>
          <td class="v">{{ frappe.utils.fmt_money(doc.net_total or doc.total or 0, currency=doc.currency) }}</td>
        </tr>
        {% if (doc.total_taxes_and_charges or 0) %}
        <tr>
          <td class="k">Taxes & Charges</td>
          <td class="v">{{ frappe.utils.fmt_money(doc.total_taxes_and_charges or 0, currency=doc.currency) }}</td>
        </tr>
        {% endif %}
        <tr class="line">
          <td class="k">Grand Total</td>
          <td class="v">{{ frappe.utils.fmt_money(doc.grand_total or doc.rounded_total or 0, currency=doc.currency) }}</td>
        </tr>
      </table>
    </div>
  </div>

  <!-- Terms & Conditions -->
  <div class="po-card">
    <div class="po-section-title">Terms & Conditions</div>
    <div class="po-terms">
      {{ doc.terms or
      "- Delivery: ____________________\n- Payment Terms: ____________________\n- Validity: ____________________\n- Notes: ____________________" }}
    </div>
  </div>

  <!-- Signatures -->
  <div class="po-sign-row">
    <div class="po-sign-box">
      <div class="po-sign-line">Prepared By</div>
      <div class="po-sign-meta">{{ prepared_by or "-" }}</div>
      <div class="po-sign-note">Procurement / Store</div>
    </div>

    <div class="po-sign-box">
      <div class="po-sign-line">Reviewed By</div>
      <div class="po-sign-meta">{{ reviewed_by or "-" }}</div>
      <div class="po-sign-note">Finance / Audit</div>
    </div>

    <div class="po-sign-box">
      <div class="po-sign-line">Approved By</div>
      <div class="po-sign-meta">{{ approved_by or "-" }}</div>
      <div class="po-sign-note">Manager Signature & Stamp</div>
    </div>
  </div>

  <!-- Contact / Call us -->
  <div class="po-contact">
    <div>
      <b>For inquiries:</b><br>
      Call / WhatsApp: +252 XX XXX XXXX<br>
      Email: info@yourcompany.com
    </div>
    <div style="text-align:right;">
      <b>Address:</b><br>
      Your Company Address Line 1<br>
      City, Country
    </div>
  </div>
</div>
